/// <summary>
/// Classe-base de todos os objectivos (condições de vitória) de um
/// <see cref="ChallengeDefinition"/>. Cada subclasse representa um objectivo
/// configurável no Inspector (ex: chegar a uma zona, recolher N itens, derrotar
/// inimigos, sobreviver X segundos, defender um NPC, resolver um puzzle via
/// variável global).
///
/// Para adicionar um novo objectivo: cria uma subclasse [System.Serializable]
/// em Data/Objectives/ com prefixo "Objective_" e implementa IsComplete()
/// (e, se fizer sentido, CurrentProgress/TargetProgress/ResetState). Aparece
/// automaticamente no botão "+ Adicionar Objectivo" do ChallengeDefinitionEditor
/// (PolymorphicListDrawer, Tarefa #10/#14).
///
/// Ciclo de vida (chamado por ChallengeManager):
/// 1. <see cref="ResetState"/> ao (re)iniciar o desafio.
/// 2. <see cref="IsComplete"/> verificado a cada frame enquanto o desafio
///    estiver activo; quando TODOS os objectivos com <see cref="required"/> = true
///    estiverem completos, o desafio termina com sucesso.
/// 3. <see cref="CurrentProgress"/>/<see cref="TargetProgress"/> alimentam o
///    HUD ("descrição: actual/total") — devolver -1 em TargetProgress para
///    objectivos binários (sem contador).
/// </summary>
[System.Serializable]
public abstract class ChallengeObjective
{
    /// <summary>Texto curto mostrado no HUD do desafio (ex: "Apanha as Sementes", "Chega ao fim").</summary>
    public string displayText;

    /// <summary>
    /// Se true (padrão), este objectivo tem de estar completo para o desafio
    /// ter sucesso. Se false, é apenas informativo/opcional (ex: bónus que não
    /// bloqueia a conclusão).
    /// </summary>
    public bool required = true;

    /// <summary>Chamado ao iniciar ou reiniciar o desafio — repõe contadores/estado interno.</summary>
    public virtual void ResetState() { }

    /// <summary>Progresso actual, para o HUD "actual/total". Devolver 0 se não aplicável.</summary>
    public virtual int CurrentProgress() => 0;

    /// <summary>Meta de progresso, para o HUD "actual/total". Devolver -1 para objectivos binários (sem contador, o HUD mostra só 'displayText').</summary>
    public virtual int TargetProgress() => -1;

    /// <summary>Devolve true quando este objectivo está cumprido.</summary>
    public abstract bool IsComplete();
}
